class Solution:
    def solve(self, nums: list[int]) -> int:
        dp = [0] * len(nums)
        dp[0] = 0
        for i in range(1, len(nums)):
            if nums[i] <= i:
                dp[i] = dp[i-1] + 1
            elif i - nums[i-1] < dp[i-1]:
                dp[i] = dp[i-1] + 1
            else:
                dp[i] = dp[i-1]
        return dp[-1] if dp[-1] != float('inf') else -1

