class Solution {
public:
    int solve(vector<int>& nums) {
        if (nums.size() == 1) return nums[0] == 0 ? -1 : 0;
        vector<int> dp(nums.size());
        dp[0] = nums[0] == 0 ? -1 : 0;
        for (int i = 1; i < nums.size(); i++) {
            dp[i] = nums[i] <= i ? dp[i-1] + 1 : (i - nums[i-1] < dp[i-1] ? dp[i-1]+1 : dp[i-1]);
        }
        return dp[nums.size() - 1] == -1 ? -1 : dp[nums.size() - 1];
    }
};

int main() {
    Solution s;
    int n;
    while (std::cin >> n) {
